namespace BlazorApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateTime(2026, 4, 10)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateTime(2026, 3, 22)),
            new(3, "Pallet Jack C", "Warehouse 1", new DateTime(2026, 5, 1)),
            new(4, "Hydraulic Press D", "Factory Floor", new DateTime(2026, 2, 15)),
            new(5, "CNC Lathe E", "Machine Shop", new DateTime(2026, 1, 30)),
            new(6, "Welding Station F", "Factory Floor", new DateTime(2026, 4, 28)),
            new(7, "Overhead Crane G", "Warehouse 3", new DateTime(2026, 5, 12)),
            new(8, "Compressor H", "Utility Room", new DateTime(2025, 12, 20)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using BlazorApp.Services
@using Microsoft.AspNetCore.Components
@inject IEquipmentService EquipmentService
@inject PersistentComponentState ApplicationState

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _equipment;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // Try to restore data persisted during prerender.
        // If found, skip the service call entirely (no double fetch).
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            _equipment = restored;
        }
        else
        {
            _equipment = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", _equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

